import React, { useState, useEffect } from "react";
import { Link, useParams } from "react-router-dom";
import { categoryAPI } from "../../api";

const Sidebar = () => {
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const { slug } = useParams();

  useEffect(() => {
    let mounted = true;
    categoryAPI.getCategories().then(res => {
      if (mounted && res.data && Array.isArray(res.data)) setCategories(res.data);
    }).catch(()=>{ if(mounted) setCategories([]); }).finally(()=> mounted && setLoading(false));
    return ()=> mounted = false;
  }, []);

  if (loading) return <aside className="sidebar">Đang tải...</aside>;

  return (
    <aside className="sidebar" style={{ width: 260 }}>
      <h4 style={{ color: "#2f855a" }}>Danh mục sản phẩm</h4>
      <ul style={{ listStyle: "none", padding: 0 }}>
        {categories.map(c => (
          <li key={c._id} style={{ padding: "8px 6px", background: slug === c.slug ? "#f0fff4" : "transparent" }}>
            <Link to={`/category/${c.slug}`}>{c.name}</Link>
          </li>
        ))}
      </ul>
    </aside>
  );
};

export default Sidebar;
